-- Тестовые данные: 20 мероприятий + 20 свиданий (Караганда)
-- Важно:
-- 1) user_id должны существовать в таблице users
-- 2) у каждого user_id только одно активное мероприятие и одно свидание
-- 3) category_id 24-37 должны быть в date_categories
-- 4) фото мероприятий: uploads/photos/seed_event_*.jpg
-- 5) фото свиданий берутся из user_photos автора
-- 6) перед вставкой при необходимости сдвиньте даты: event_date / date_time >= NOW()

-- Мероприятия (20 шт, status=approved)

-- Свидания (20 шт)

-- Фото профиля user #73 (для свидания без фото)
SELECT 73, 'seed_user_73.jpg', NOW()
WHERE NOT EXISTS (SELECT 1 FROM user_photos WHERE user_id = 73);
